```java
package com.codequest.catalog;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class Application {
    public static void main(String[] args) {
        SpringApplication.run(Application.class, args);
        System.out.println("Product Catalog is running!");
    }
}
```

```java
@Service
public class ProductCatalogService {

    @Value("${catalog.max-products:100}")
    private int maxProducts;  // reads from properties, defaults to 100

    private final List<String> products = new ArrayList<>();

    @PostConstruct
    public void loadProducts() {
        System.out.println("Loading catalog (max: " + maxProducts + " products)...");
        products.addAll(List.of("Wireless Mouse", "Mechanical Keyboard", "USB-C Hub"));
        System.out.println("Loaded " + products.size() + " products");
    }

    public List<String> getAll()      { return Collections.unmodifiableList(products); }
    public int          getMaxProducts() { return maxProducts; }
}
```

```java
@Component
public class StartupRunner implements CommandLineRunner {

    private final ProductCatalogService catalogService;

    @Autowired
    StartupRunner(ProductCatalogService catalogService) {
        this.catalogService = catalogService;  // Spring injected this!
    }

    @Override
    public void run(String... args) {
        System.out.println("\n=== Catalog Startup ===");
        System.out.println("Max products: " + catalogService.getMaxProducts());
        System.out.println("Products: " + catalogService.getAll());
    }
}
```

