// Application.java:
@SpringBootApplication
public class Application {
    public static void main(String[] args) { SpringApplication.run(Application.class, args); }
}

// ProductCatalogService.java:
@Service
public class ProductCatalogService {
    @Value("${catalog.max-products:100}")
    private int maxProducts;
    private final List<String> products = new ArrayList<>();

    @PostConstruct
    public void loadProducts() {
        products.addAll(List.of("Wireless Mouse", "Keyboard", "USB Hub"));
        System.out.println("Catalog loaded: " + products.size() + " items (max: " + maxProducts + ")");
    }
    public List<String> getAll()      { return Collections.unmodifiableList(products); }
    public int getMaxProducts()        { return maxProducts; }
}

// StartupRunner.java:
@Component
public class StartupRunner implements CommandLineRunner {
    private final ProductCatalogService service;
    StartupRunner(ProductCatalogService s) { service = s; }  // @Autowired optional on single constructor

    @Override
    public void run(String... args) {
        System.out.println("Products: " + service.getAll());
        System.out.println("Max allowed: " + service.getMaxProducts());
    }
}
